import createReducer from '~/redux/store/createReducer'

/**
 * Types
 */
export const Types = {
  GET: 'updatePassword/get',
  SUCESS: 'updatePassword/sucess',
  FAILED: 'updatePassword/failed',
  CLEAR: 'updatePassword/clear',
}
/**
 * Initial State
 */
interface initialStateProps {
  loading: boolean
  error: boolean
  data: string | boolean | number
  updatePasswordSuccess: boolean;
}

const initialState: initialStateProps = {
  loading: false,
  error: false,
  data: '',
  updatePasswordSuccess: false,
}

/**
 * Reducers
 */
const updatePersonalPasswordReducer = createReducer(initialState, {
  [Types.GET](state: initialStateProps) {
    return {
      ...state,
      loading: true,
      updatePasswordSuccess: false,
    }
  },
  [Types.SUCESS](state: initialStateProps, { data }: any) {
    return {
      ...state,
      data,
      loading: false,
      error: false,
      updatePasswordSuccess: true,
    }
  },
  [Types.FAILED](state: initialStateProps) {
    return {
      ...state,
      loading: false,
      error: true,
      updatePasswordSuccess: false,
    }
  },
  [Types.CLEAR](state: initialStateProps) {
    return {
      ...state,
      ...initialState,
    };
  },
})
/**
 * Actions
 */
const Creators = {
  getUpdatePersonalPassword: (senhaAtual: string, senhaNova: string) => ({
    type: Types.GET,
    senhaAtual,
    senhaNova,
  }),
  successUpdatePersonalPassword: (data: number) => ({
    type: Types.SUCESS,
    data,
  }),
  failedUpdatePersonalPassword: () => ({
    type: Types.FAILED,
  }),
  clearUpdatePersonalPassword: () => ({
    type: Types.CLEAR,
  }),
}
/**/
export default updatePersonalPasswordReducer;

