import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum validateCardPasswordTypes {
  REQUEST = '@validateCardPassword/VALIDATE_CARD_PASSWORD_REQUEST',
  SUCCESS = '@validateCardPassword/VALIDATE_CARD_PASSWORD_SUCCESS',
  FAILED = '@validateCardPassword/VALIDATE_CARD_PASSWORD_FAILED',
  CLEAN = '@validateCardPassword/VALIDATE_CARD_PASSWORD_CLEAN',
}

export type PasswordValid = {
  valid: boolean;
};

export interface ValidateCardPasswordResponse {
  code: number;
  message: string;
  data?: PasswordValid;
}

type CallbackValidateCardPassword = (response: ValidateCardPasswordResponse) => void;

export interface validateCardPasswordReducerProps {
  isLoading: boolean;
  isError: boolean;
  code: number | undefined;
  message: string;
  data: PasswordValid | undefined;
  isValid: boolean;
}

type State = validateCardPasswordReducerProps;

const initialState: validateCardPasswordReducerProps = {
  isLoading: false,
  isError: false,
  code: undefined,
  message: '',
  data: undefined,
  isValid: false,
};

const validateCardPasswordReducer = createReducer(initialState, {
  [validateCardPasswordTypes.REQUEST](state: State) {
    return {
      ...state,
      isLoading: true,
    };
  },
  [validateCardPasswordTypes.SUCCESS](
    state: State,
    { data: { code, data, message } }: { data: ValidateCardPasswordResponse }
  ) {
    return {
      ...state,
      code,
      data,
      message,
      isLoading: false,
      isError: false,
    };
  },
  [validateCardPasswordTypes.FAILED](
    state: State,
    { data }: { data: ValidateCardPasswordResponse }
  ) {
    return {
      ...state,
      code: data?.code,
      data: data?.data,
      message: data?.message,
      isLoading: false,
      isError: true,
    };
  },
  [validateCardPasswordTypes.CLEAN](): State {
    return initialState;
  },
});

type ValidateCardPasswordActionsTypes = {
  validateCardPasswordRequest: (
    password: string,
    callback?: CallbackValidateCardPassword
  ) => Action;
  validateCardPasswordSuccess: (data?: ValidateCardPasswordResponse) => Action;
  validateCardPasswordFailed: (data?: ValidateCardPasswordResponse) => Action;
  validateCardPasswordClean: () => Action;
};

export const validateCardPasswordActions: ValidateCardPasswordActionsTypes = {
  validateCardPasswordRequest: (
    password: string,
    callback?: (response: ValidateCardPasswordResponse) => void
  ) => ({
    type: validateCardPasswordTypes.REQUEST,
    password,
    callback,
  }),
  validateCardPasswordSuccess: (data?: ValidateCardPasswordResponse) => ({
    type: validateCardPasswordTypes.SUCCESS,
    data,
  }),
  validateCardPasswordFailed: (data?: ValidateCardPasswordResponse) => ({
    type: validateCardPasswordTypes.FAILED,
    data,
  }),
  validateCardPasswordClean: () => ({
    type: validateCardPasswordTypes.CLEAN,
  }),
};

export default validateCardPasswordReducer;

