import createReducer from '~/redux/store/createReducer';
import { Action } from 'redux';

export enum WithdrawTypes {
  GET_WITHDRAW = '@withdraw/GETWITHDRAW',
  GET_WITHDRAW_SUCCESS = '@withdraw/GETWITHDRAWSUCCESS',
  GET_WITHDRAW_ERROR = '@withdraw/GETWITHDRAWERROR',
  UNLOCK_WITHDRAW = '@withdraw/UNLOCK_WITHDRAW',
}

export interface WithdrawResponse {
  code: number;
  message: string;
  data: {
    message: string;
  };
}
interface WithdrawRequest {
  CPF: string | undefined;
  Conta: string;
}

export interface WithdrawProps {
  isLoading: boolean;
  isError: boolean;
  withdrawEnable: boolean | undefined;
}

type State = WithdrawProps;

const initialState: WithdrawProps = {
  withdrawEnable: undefined,
  isError: false,
  isLoading: false,
};

export type withdrawCallback = (data: {
  statusCode: number | undefined;
  response: boolean;
}) => void;

const withdrawReducer = createReducer(initialState, {
  [WithdrawTypes.GET_WITHDRAW](state: State): State {
    return {
      ...state,
      isLoading: true,
      isError: false,
    };
  },
  [WithdrawTypes.GET_WITHDRAW_SUCCESS](
    state: State,
    { withdrawEnable }: { withdrawEnable: boolean },
  ): State {
    return {
      ...state,
      isLoading: false,
      withdrawEnable,
      isError: false,
    };
  },
  [WithdrawTypes.GET_WITHDRAW_ERROR](state: State): State {
    return {
      ...state,
      isError: true,
      isLoading: false,
    };
  },
  [WithdrawTypes.UNLOCK_WITHDRAW](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
});

interface WithdrawActions {
  getWithdraw: (lastFourNumbers: string, callback: withdrawCallback) => Action;
  getWithdrawSuccess: (withdrawEnable: boolean) => Action;
  getWithdrawError: () => Action;
  unlockWithdraw: (
    lastFourNumbers: string,
    active: boolean,
    callback: withdrawCallback,
  ) => Action;
}

export const withdrawActions: WithdrawActions = {
  getWithdraw: (lastFourNumbers, callback) => ({
    type: WithdrawTypes.GET_WITHDRAW,
    lastFourNumbers,
    callback,
  }),
  getWithdrawSuccess: withdrawEnable => ({
    type: WithdrawTypes.GET_WITHDRAW_SUCCESS,
    withdrawEnable,
  }),
  getWithdrawError: () => ({
    type: WithdrawTypes.GET_WITHDRAW_ERROR,
  }),
  unlockWithdraw: (lastFourNumbers, active, callback) => ({
    type: WithdrawTypes.UNLOCK_WITHDRAW,
    lastFourNumbers,
    active,
    callback,
  }),
};

export default withdrawReducer;

