import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum PasswordTypes {
  REQUEST = '@password/PASSWORD_REQUEST',
  SUCCESS = '@password/PASSWORD_SUCCESS',
  FAILED = '@password/PASSWORD_FAILED',
  CLEAR = '@password/PASSWORD_CLEAR',
}

export type PasswordCallback = (data: {
  statusCode: number | undefined;
  password: string | undefined;
}) => void;

export interface PasswordResponse {
  code: number;
  message: string;
  data: string;
}

export interface PasswordReducerProps {
  isLoading: boolean;
  isError: boolean;
}

type State = PasswordReducerProps;

const initialState: PasswordReducerProps = {
  isLoading: false,
  isError: false,
};

const passwordReducer = createReducer(initialState, {
  [PasswordTypes.REQUEST](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [PasswordTypes.SUCCESS](): State {
    return {
      isLoading: false,
      isError: false,
    };
  },
  [PasswordTypes.FAILED](): State {
    return {
      isLoading: false,
      isError: true,
    };
  },
  [PasswordTypes.CLEAR](): State {
    return initialState;
  },
});

type PasswordActions = {
  passwordRequest: (
    lastFourNumbers: string,
    callback: PasswordCallback,
  ) => Action;
  passwordSuccess: () => Action;
  passwordFailed: () => Action;
  passwordClear: () => Action;
};

export const passwordActions: PasswordActions = {
  passwordRequest: (lastFourNumbers: string, callback: PasswordCallback) => ({
    type: PasswordTypes.REQUEST,
    lastFourNumbers,
    callback,
  }),
  passwordSuccess: () => ({
    type: PasswordTypes.SUCCESS,
  }),
  passwordFailed: () => ({
    type: PasswordTypes.FAILED,
  }),
  passwordClear: () => ({
    type: PasswordTypes.CLEAR,
  }),
};

export default passwordReducer;

